Code Good:
// Interface: defines WHAT
interface Exportable {
    public function export(string $format): string;
    public function supportedFormats(): array;
}

// Abstract class: provides shared HOW
abstract class BaseExporter implements Exportable {
    public function export(string $format): string {
        if (!in_array($format, $this->supportedFormats())) {
            throw new UnsupportedFormatException($format);
        }
        return $this->doExport($format);
    }
    abstract protected function doExport(string $format): string;
}

class UserExporter extends BaseExporter {
    public function supportedFormats(): array { return ['csv', 'json']; }
    protected function doExport(string $format): string { ... }
}

