Code Good:
// Focused trait:
trait HasTimestamps {
    public function getCreatedAtForHumans(): string {
        return $this->created_at->diffForHumans();
    }
    public function isRecent(int $days = 7): bool {
        return $this->created_at->isAfter(now()->subDays($days));
    }
}

trait Sluggable {
    public static function bootSluggable(): void {
        static::creating(function ($model) {
            $model->slug = Str::slug($model->{$model->slugSource()});
        });
    }
    abstract protected function slugSource(): string;
}

class Article extends Model {
    use HasTimestamps, Sluggable;
    protected function slugSource(): string { return 'title'; }
}

